function mergeFlags(...sources) {
  const flags = {};
  for (const source of sources) {
    if (!source) continue;
    Object.assign(flags, source.flags || {});
    for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) {
      if (source[key] !== undefined && source[key] !== null && source[key] !== '') flags[key] = normalizeBoolean(source[key], flags[key]);
    }
  }
  return flags;
}

function normalizeBoolean(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function flagEnabled(data, name, fallback = true) {
